from collections import defaultdict

class Solution(object):
    def queryResults(self, limit, queries):
        ball_color = {}    # ball -> current color
        color_count = defaultdict(int)  # color -> number of balls with that color
        distinct = 0
        result = []
        for x, y in queries:
            if x in ball_color:
                old_c = ball_color[x]
                color_count[old_c] -= 1
                if color_count[old_c] == 0:
                    distinct -= 1
                    del color_count[old_c]
            ball_color[x] = y
            color_count[y] += 1
            if color_count[y] == 1:
                distinct += 1
            result.append(distinct)
        return result
